# Filter out rows where numeric is "0" or empty, strip whitespace
filtered_items = []
for item in items:
    numeric = item['numeric'].strip()
    if numeric and numeric != "0":
        filtered_items.append(item)

# Sort by numeric (entity_code) as integers
filtered_items.sort(key=lambda x: int(x['numeric']))

# Prepare output directory
output_path = Path(__file__).parent / "buildings.csv"
output_path.parent.mkdir(parents=True, exist_ok=True)

# Write CSV
with open(output_path, 'w', newline='') as f:
    writer = csv.writer(f)
    writer.writerow(['entity_code', 'building_name', 'address', 'city', 'zip', 'type', 'units'])

    for item in filtered_items:
        writer.writerow([
            item['numeric'].strip(),
            item['name'].strip(),
            item['text8'].strip(),
            item['text7'].strip(),
            item['text03'].strip(),
            item['status1'].strip(),
            item['numbers9'].strip(),
        ])

print(f"CSV file created: {output_path}")
print(f"Total rows written: {len(filtered_items)}")
